def build_user_data_message(
    *,
    event_type: str,
    user_id: str,
    emails: Optional[List[str]] = None,
    phone_numbers: Optional[List[str]] = None,
    addresses: Optional[List[Dict[str, Any]]] = None,
    full_name: Optional[str] = None,
    source: Optional[str] = None,
    trace_id: Optional[str] = None,
    metadata: Optional[Dict[str, Any]] = None,
) -> UserDataMessage:
    addr_objs: List[Address] = []
    if addresses:
        for a in addresses:
            addr_objs.append(
                Address(
                    line1=str(a.get("line1", "")),
                    line2=a.get("line2"),
                    city=a.get("city"),
                    region=a.get("region"),
                    postal_code=a.get("postal_code"),
                    country=a.get("country"),
                )
            )

    pii = UserPII(
        user_id=str(user_id),
        emails=[str(x) for x in (emails or [])],
        phone_numbers=[str(x) for x in (phone_numbers or [])],
        addresses=addr_objs,
        full_name=full_name,
    )

    return UserDataMessage(
        event_type=str(event_type),
        pii=pii,
        source=source,
        trace_id=trace_id,
        metadata=metadata or {},
    )


